    // Load State from sync backend
    async function loadSyncedState() {
      if (!envId) {
        updateSyncStatusIndicator("local");
        return;
      }
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`);
        const json = await res.json();
        if (json.data && Array.isArray(json.data.tasks) && Array.isArray(json.data.facts)) {
          state.tasks = json.data.tasks;
          state.facts = json.data.facts;
          state.services = json.data.services || SERVICES;
          renderApp();
          updateSyncStatusIndicator("synced");
        } else if (!json.data) {
          await saveSyncedState(state);
          updateSyncStatusIndicator("synced");
        }
      } catch (err) {
        console.error("Synced load failure:", err);
        updateSyncStatusIndicator("error");
      }
    }

    // Save state to sync server
    async function saveSyncedState(newState) {
      if (!envId) return;
      try {
        const res = await fetch(`/api/sync/${envId}/${syncKey}`, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ data: newState })
        });
        if (res.ok) {
          updateSyncStatusIndicator("synced");
        } else {
          updateSyncStatusIndicator("error");
        }
      } catch (err) {
        console.error("Synced save failure:", err);
        updateSyncStatusIndicator("error");
      }
    }

    function updateSyncStatusIndicator(status) {
      const dot = document.getElementById("sync-dot");
      const text = document.getElementById("sync-text");
      const badge = document.getElementById("sync-badge");

      if (status === "synced") {
        dot.className = "w-2 h-2 rounded-full bg-green-500 animate-pulse";
        text.innerText = "Synced";
        badge.className = "flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium bg-green-50 text-green-700 border border-green-200";
      } else if (status === "local") {
        dot.className = "w-2 h-2 rounded-full bg-blue-500";
        text.innerText = "Local Mode";
        badge.className = "flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium bg-blue-50 text-blue-700 border border-blue-200";
      } else {
        dot.className = "w-2 h-2 rounded-full bg-red-500";
        text.innerText = "Sync Alert";
        badge.className = "flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-medium bg-red-50 text-red-700 border border-red-200";
