    // Simulates a live sandbox terminal execution for the active task
    function simulateActiveTaskExecution() {
      const task = state.tasks.find(t => t.id === state.selectedTaskId);
      if (!task) return;

      const ptyConsole = document.getElementById("pty-console");
      const badge = document.getElementById("pty-status-badge");

      badge.innerText = "RUNNING";
      badge.className = "px-2.5 py-1 text-[11px] font-medium rounded-full bg-blue-600 text-white animate-pulse";

      ptyConsole.innerHTML = `
        <div class="text-blue-400">[INIT] Spawning hermetic container capsule...</div>
        <div class="text-gray-400">[PTY] Working Directory mapped: /tmp/ollie-sandbox-workspace/</div>
      `;

      let progressTurn = 0;
      const simulationLogs = [
        `[PTY] Injecting temporary scope Gaia OAuth token for delegator: ${task.assignee}`,
        "[PTY] Invoking internal build suite fig check-ins...",
        "[PTY] Running SKYBUILD=1 blaze test //java/com/google/workspace/ollie/...",
        "[COMPILER-AST] Harvesting compilation metadata errors...",
        "[COMPILER-AST] Warning: unreferenced imports in task_service_spanner_impl.cc:32",
        "[PTY] Compiling dependency trees and linking SCANN Scaffolding libraries...",
        "[SUCCESS] 21 tests passed successfully in Capsule Container.",
        "[PTY-COMMIT] Creating internal Git commit diff..."
      ];

      if (executionSimulationTimer) clearInterval(executionSimulationTimer);

      executionSimulationTimer = setInterval(() => {
        if (progressTurn < simulationLogs.length) {
          const logLine = document.createElement("div");
          logLine.className = "mb-1";
          logLine.innerText = simulationLogs[progressTurn];
          ptyConsole.appendChild(logLine);
          ptyConsole.scrollTop = ptyConsole.scrollHeight;
          progressTurn++;
        } else {
          clearInterval(executionSimulationTimer);
          executionSimulationTimer = null;
          badge.innerText = "PENDING_REVIEW";
          badge.className = "px-2.5 py-1 text-[11px] font-medium rounded-full bg-purple-100 text-purple-800";

          const successDiv = document.createElement("div");
          successDiv.className = "text-green-400 font-semibold mt-2";
          successDiv.innerText = "[PTY RUN COMPLETE] Sandbox execution succeeded. Awaiting final user approval.";
          ptyConsole.appendChild(successDiv);
          ptyConsole.scrollTop = ptyConsole.scrollHeight;

          // Update task state array and save
          task.status = "IN_PROGRESS";
          renderTaskMatrix();
          saveSyncedState(state);
        }
      }, 1000);
    }

