      document.getElementById("new-task-backdrop").classList.add("hidden");
      document.getElementById("task-title").value = "";
      document.getElementById("task-desc").value = "";
    }

    function addNewTask() {
      const titleInput = document.getElementById("task-title");
      const descInput = document.getElementById("task-desc");
      const assigneeInput = document.getElementById("task-assignee");
      const delegationInput = document.getElementById("task-delegation");

      const title = titleInput.value.trim();
      const desc = descInput.value.trim();
      const assignee = assigneeInput.value;
      const delegation = delegationInput.value;

      if (!title) {
        alert("Please specify a valid task title.");
        return;
      }

      const newTask = {
        id: "task-" + Date.now().toString().slice(-4),
        title,
        description: desc || "No description provided.",
        status: "TRIAGED",
        assignee,
        delegation
      };

      state.tasks.push(newTask);
      closeCreateTaskModal();
      renderTaskMatrix();
      saveSyncedState(state);
    }


    // ================== MEMORY INSIGHTS LOGIC ==================

    function renderMemoryFacts() {
      const container = document.getElementById("memory-facts-container");
      if (!container) return;

      // Filter state facts based on active tier
      let filtered = state.facts;
      if (memoryTierFilter !== "all") {
        filtered = state.facts.filter(f => f.tier === memoryTierFilter);
      }

      // Sort by search relevance if input has values
      const searchInput = document.getElementById("memory-search-input").value.trim().toLowerCase();
      if (searchInput) {
        filtered.forEach(fact => {
          let score = 0;
          if (fact.title.toLowerCase().includes(searchInput)) score += 5;
          if (fact.content.toLowerCase().includes(searchInput)) score += 3;
          if (fact.category.toLowerCase().includes(searchInput)) score += 2;
          fact.relevance = score;
        });
        filtered = filtered.filter(f => f.relevance > 0);
        filtered.sort((a, b) => b.relevance - a.relevance);
        document.getElementById("search-analytics-badge").innerHTML = `Found <span class="font-medium text-gray-800">${filtered.length}</span> matches in <span class="font-medium text-gray-800">0.02ms</span>`;
      } else {
        filtered.forEach(f => f.relevance = 1.0);
        document.getElementById("search-analytics-badge").innerHTML = `Indexed <span class="font-medium text-gray-800">${filtered.length}</span> facts in Memory DB`;
      }

      if (filtered.length === 0) {
        container.innerHTML = `
          <div class="text-center py-12 border border-dashed border-gray-200 rounded-xl">
            <p class="text-sm text-gray-500">No consolidated facts found in this tier scope.</p>
          </div>
        `;
        return;
      }

      container.innerHTML = filtered.map(fact => {
        let tierBadgeClass = "bg-gray-100 text-gray-600 border border-gray-200";
        if (fact.tier === "private") tierBadgeClass = "bg-rose-50 text-rose-700 border border-rose-100";
        else if (fact.tier === "workstream") tierBadgeClass = "bg-sky-50 text-sky-700 border border-sky-100";
        else if (fact.tier === "team") tierBadgeClass = "bg-indigo-50 text-indigo-700 border border-indigo-100";
        else if (fact.tier === "global") tierBadgeClass = "bg-amber-50 text-amber-700 border border-amber-100";

        const relevanceDisplay = searchInput ? `
          <span class="text-[11px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded border border-green-100">
            Sim Score: ${(0.75 + (fact.relevance / 10)).toFixed(2)}
          </span>
        ` : "";

        return `
          <div class="p-4 border border-gray-200 rounded-xl hover:shadow-sm transition-all bg-white space-y-2">
            <div class="flex items-start justify-between gap-3">
              <div class="flex items-center gap-2 flex-wrap">
                <span class="text-xs font-semibold text-gray-900">${fact.title}</span>
                <span class="text-[10px] uppercase font-bold tracking-wider px-2 py-0.5 rounded-full ${tierBadgeClass}">${fact.tier}</span>
                <span class="text-[10px] text-gray-500 bg-gray-50 px-1.5 py-0.5 rounded border font-medium">${fact.category}</span>
              </div>
              <div class="flex items-center gap-2">
                ${relevanceDisplay}
                <button class="text-gray-300 hover:text-red-500 transition-colors p-0.5" onclick="deleteMemoryFact('${fact.id}')" title="Prune Fact">
                  <svg class="w-4 h-4" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
                    <path stroke-linecap="round" stroke-linejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"></path>
                  </svg>
                </button>
              </div>
            </div>
            <p class="text-xs text-gray-700 leading-relaxed">${fact.content}</p>
            <div class="flex items-center justify-between text-[11px] text-gray-500 border-t border-gray-50 pt-2">
              <span>Author: <span class="font-medium text-gray-700">${fact.author}</span></span>
              <span>Vector State: <span class="text-green-600 font-mono font-bold">SYNCS_COMMITTED</span></span>
            </div>
          </div>
        `;
      }).join("");
    }

    function filterMemoryTier(tier) {
      memoryTierFilter = tier;

      const tiers = ["all", "private", "workstream", "team", "global"];
      tiers.forEach(t => {
        const btn = document.getElementById(`tier-btn-${t}`);
        if (t === tier) {
          btn.className = "w-full text-left text-xs p-2.5 rounded-lg border border-blue-100 bg-blue-50 text-blue-700 font-medium flex items-center justify-between";
        } else {
          btn.className = "w-full text-left text-xs p-2.5 rounded-lg border border-gray-100 hover:bg-gray-50 text-gray-700 flex items-center justify-between";
        }
      });

      renderMemoryFacts();
    }

    function updateMemoryTierCounts() {
      document.getElementById("badge-all-count").innerText = state.facts.length;
      document.getElementById("badge-private-count").innerText = state.facts.filter(f => f.tier === "private").length;
      document.getElementById("badge-workstream-count").innerText = state.facts.filter(f => f.tier === "workstream").length;
      document.getElementById("badge-team-count").innerText = state.facts.filter(f => f.tier === "team").length;
      document.getElementById("badge-global-count").innerText = state.facts.filter(f => f.tier === "global").length;
    }

    function executeMemoryQuery() {
      renderMemoryFacts();
    }

    function proposeMemoryFact() {
      const titleInput = document.getElementById("new-fact-title");
      const contentInput = document.getElementById("new-fact-content");
      const tierInput = document.getElementById("new-fact-tier");

      const title = titleInput.value.trim();
      const content = contentInput.value.trim();
      const tier = tierInput.value;

      if (!title || !content) {
        alert("Please complete the title and content elements before proposing a fact.");
        return;
      }

      const newFact = {
        id: "fact-" + Date.now().toString().slice(-4),
        title,
        content,
        tier,
        category: "ARCHITECTURE",
        author: "Console Operator",
        relevance: 1.0
      };

      state.facts.push(newFact);
      titleInput.value = "";
      contentInput.value = "";

      renderMemoryFacts();
      updateMemoryTierCounts();
      saveSyncedState(state);
    }

    function deleteMemoryFact(id) {
      state.facts = state.facts.filter(f => f.id !== id);
      renderMemoryFacts();
      updateMemoryTierCounts();
      saveSyncedState(state);
    }

    // Run Initialization routine on window load
    window.onload = init;
  </script>
</body>
</html>
