  DELEGATION_TARGET_HUMAN_ONLY = 1;
  DELEGATION_TARGET_PERSONAL_AGENT = 2;
  DELEGATION_TARGET_WORKSTREAM_AGENT = 3;
  DELEGATION_TARGET_HYBRID = 4;
}


