  status STRING(32) NOT NULL, -- "UNTRIAGED", "TRIAGED", "IN_PROGRESS", "PENDING_REVIEW", "COMPLETED", "CANCELLED"
  priority STRING(16) NOT NULL, -- "P0", "P1", "P2", "P3", "P4"
  visibility STRING(32) NOT NULL, -- "private", "workstream_visible", "shared_restricted"
  assignee_gaia_id STRING(64),
  delegation_target STRING(32) NOT NULL, -- "HUMAN_ONLY", "PERSONAL_AGENT", "WORKSTREAM_AGENT", "HYBRID"
  
  -- Multi-source provenance array storing originating trigger URIs
  original_sources ARRAY<STRING(1024)>,
  
  -- 768-dimensional float array for native ScaNN similarity indexing
  vector_embedding ARRAY<FLOAT64>,
  
  requires_hitl_approval BOOL NOT NULL DEFAULT (true),
  create_time TIMESTAMP NOT NULL OPTIONS (allow_commit_timestamp=true),
  update_time TIMESTAMP NOT NULL OPTIONS (allow_commit_timestamp=true),
  completed_time TIMESTAMP,
  etag STRING(64) NOT NULL,
  CONSTRAINT FK_Tasks_Parent FOREIGN KEY (workstream_id, parent_task_id) REFERENCES Tasks (workstream_id, task_id)
