  INTERLEAVE IN PARENT Workstreams ON DELETE CASCADE;


-- Native ScaNN Vector Index for Semantic Duplicate Detection and Auto-Routing
CREATE VECTOR INDEX Tasks_Embedding_Index
ON Tasks(vector_embedding)
STORING (title, status, assignee_gaia_id)
OPTIONS (
  distance_type = 'COSINE',
  index_type = 'SCANN',
  tree_ah_config = '{"num_leaves": 1000, "num_leaves_to_search": 10}'
);


CREATE INDEX TasksByAssigneeAndStatus ON Tasks(assignee_gaia_id, status);
